createScene(name){const scene=new Scene(this,name||"scene_"+this.scenes.length);this.scenes.push(scene);return scene}
setActiveScene(scene){if(typeof scene==="string"){scene=this.getScene(scene)}if(scene){this.activeScene=scene;this.renderer.setScene(scene)}return this}
