createDodecahedron(radius,detail){return new DodecahedronGeometry(radius,detail)}
createOctahedron(radius,detail){return new OctahedronGeometry(radius,detail)}
createTetrahedron(radius,detail){return new TetrahedronGeometry(radius,detail)}
createRing(innerRadius,outerRadius,segments){return new RingGeometry(innerRadius,outerRadius,segments)}
createLathe(points,segments,phiStart,phiLength){return new LatheGeometry(points,segments,phiStart,phiLength)}
createExtrude(shape,settings){return new ExtrudeGeometry(shape,settings)}
createShape(points){return new Shape(points)}
createMaterial(options){return new Material(options)}
createStandardMaterial(options){return new StandardMaterial(options)}
createPhongMaterial(options){return new PhongMaterial(options)}
createLambertMaterial(options){return new LambertMaterial(options)}
createBasicMaterial(options){return new BasicMaterial(options)}
createTexture(image,options){return new Texture(image,options)}
createCubeTexture(images,options){return new CubeTexture(images,options)}
createAmbientLight(color,intensity){return new AmbientLight(color,intensity)}
createDirectionalLight(color,intensity,position){return new DirectionalLight(color,intensity,position)}
createPointLight(color,intensity,position,distance,decay){return new PointLight(color,intensity,position,distance,decay)}
createSpotLight(color,intensity,position,direction,angle,penumbra,decay,distance){return new SpotLight(color,intensity,position,direction,angle,penumbra,decay,distance)}
createHemisphereLight(skyColor,groundColor,intensity){return new HemisphereLight(skyColor,groundColor,intensity)}
createRectAreaLight(color,intensity,width,height,position){return new RectAreaLight(color,intensity,width,height,position)}
createCamera(fov,aspect,near,far){return new Camera(fov,aspect,near,far)}
createOrthographicCamera(left,right,bottom,top,near,far){return new OrthographicCamera(left,right,bottom,top,near,far)}
createPerspectiveCamera(fov,aspect,near,far){return new PerspectiveCamera(fov,aspect,near,far)}
createNode(name){return new Node(this,name)}
createGroup(name){return new Group(this,name)}
createSkeleton(bones){return new Skeleton(bones)}
createBone(name){return new Bone(name)}
createSkinnedMesh(geometry,material,skeleton){return new SkinnedMesh(this,geometry,material,skeleton)}
createAnimationClip(name,duration,tracks){return new AnimationClip(name,duration,tracks)}
createAnimationTrack(target,property,keys){return new AnimationTrack(target,property,keys)}
createAnimationController(target){return new AnimationController(this,target)}
createRigidBody(options){return new RigidBody(options)}
createCollisionShape(type,params){return new CollisionShape(type,params)}
createTerrain(width,height,segments){return new Terrain(this,width,height,segments)}
createNavmesh(geometry){return new Navmesh(geometry)}
createPathfinder(navmesh){return new Pathfinder(navmesh)}
loadModel(url,options){return this._loadAsset(url,"model",options)}
loadTexture(url,options){return this._loadAsset(url,"texture",options)}
loadAudio(url,options){return this._loadAsset(url,"audio",options)}
_loadAsset(url,type,options){return new Promise((resolve,reject)=>{const loader=new AssetLoader(this);loader.load(url,type,options).then(resolve).catch(reject)})}
getTime(){return this.globalTime}
getDeltaTime(){return this.deltaTime}
getFPS(){return 1/this.deltaTime}
resize(width,height){this.viewportWidth=width||window.innerWidth;this.viewportHeight=height||window.innerHeight;if(this.renderer){this.renderer.resize(this.viewportWidth,this.viewportHeight)}return this}
setClearColor(color,alpha){if(this.renderer){this.renderer.setClearColor(color,alpha)}return this}
setBackground(color){if(this.activeScene){this.activeScene.background=color}return this}
setFog(color,density,near,far){if(this.activeScene){this.activeScene.fog=new Fog(color,density,near,far)}return this}
