setColor(color){this.color=color instanceof Color?color:new Color(color);this._updateUniforms();return this}
setAmbient(color){this.ambientColor=color instanceof Color?color:new Color(color);this._updateUniforms();return this}
setDiffuse(color){this.diffuseColor=color instanceof Color?color:new Color(color);this._updateUniforms();return this}
setSpecular(color){this.specularColor=color instanceof Color?color:new Color(color);this._updateUniforms();return this}
