multiplyMatrices(a,b){const ae=a.elements,be=b.elements;const a00=ae[0],a01=ae[1],a02=ae[2],a03=ae[3];const a10=ae[4],a11=ae[5],a12=ae[6],a13=ae[7];const a20=ae[8],a21=ae[9],a22=ae[10],a23=ae[11];const a30=ae[12],a31=ae[13],a32=ae[14],a33=ae[15];const b00=be[0],b01=be[1],b02=be[2],b03=be[3];const b10=be[4],b11=be[5],b12=be[6],b13=be[7];const b20=be[8],b21=be[9],b22=be[10],b23=be[11];const b30=be[12],b31=be[13],b32=be[14],b33=be[15];this.elements[0]=a00*b00+a01*b10+a02*b20+a03*b30;this.elements[1]=a00*b01+a01*b11+a02*b21+a03*b31;this.elements[2]=a00*b02+a01*b12+a02*b22+a03*b32;this.elements[3]=a00*b03+a01*b13+a02*b23+a03*b33;this.elements[4]=a10*b00+a11*b10+a12*b20+a13*b30;this.elements[5]=a10*b01+a11*b11+a12*b21+a13*b31;this.elements[6]=a10*b02+a11*b12+a12*b22+a13*b32;this.elements[7]=a10*b03+a11*b13+a12*b23+a13*b33;this.elements[8]=a20*b00+a21*b10+a22*b20+a23*b30;this.elements[9]=a20*b01+a21*b11+a22*b21+a23*b31;this.elements[10]=a20*b02+a21*b12+a22*b22+a23*b32;this.elements[11]=a20*b03+a21*b13+a22*b23+a23*b33;this.elements[12]=a30*b00+a31*b10+a32*b20+a33*b30;this.elements[13]=a30*b01+a31*b11+a32*b21+a33*b31;this.elements[14]=a30*b02+a31*b12+a32*b22+a33*b32;this.elements[15]=a30*b03+a31*b13+a32*b23+a33*b33;return this}
