determinant(){const e=this.elements;const a00=e[0],a01=e[1],a02=e[2],a03=e[3];const a10=e[4],a11=e[5],a12=e[6],a13=e[7];const a20=e[8],a21=e[9],a22=e[10],a23=e[11];const a30=e[12],a31=e[13],a32=e[14],a33=e[15];return a00*(a11*(a22*a33-a23*a32)-a12*(a21*a33-a23*a31)+a13*(a21*a32-a22*a31))-a01*(a10*(a22*a33-a23*a32)-a12*(a20*a33-a23*a30)+a13*(a20*a32-a22*a30))+a02*(a10*(a21*a33-a23*a31)-a11*(a20*a33-a23*a30)+a13*(a20*a31-a21*a30))-a03*(a10*(a21*a32-a22*a31)-a11*(a20*a32-a22*a30)+a12*(a20*a31-a21*a30))}
invert(){const e=this.elements;const det=this.determinant();if(Math.abs(det)<1e-8)return this.identity();const invDet=1/det;const a00=e[0],a01=e[1],a02=e[2],a03=e[3];const a10=e[4],a11=e[5],a12=e[6],a13=e[7];const a20=e[8],a21=e[9],a22=e[10],a23=e[11];const a30=e[12],a31=e[13],a32=e[14],a33=e[15];this.elements[0]=(a11*(a22*a33-a23*a32)-a12*(a21*a33-a23*a31)+a13*(a21*a32-a22*a31))*invDet;this.elements[1]=(-a01*(a22*a33-a23*a32)+a02*(a21*a33-a23*a31)-a03*(a21*a32-a22*a31))*invDet;this.elements[2]=(a01*(a12*a33-a13*a32)-a02*(a11*a33-a13*a31)+a03*(a11*a32-a12*a31))*invDet;this.elements[3]=(-a01*(a12*a23-a13*a22)+a02*(a11*a23-a13*a21)-a03*(a11*a22-a12*a21))*invDet;this.elements[4]=(-a10*(a22*a33-a23*a32)+a12*(a20*a33-a23*a30)-a13*(a20*a32-a22*a30))*invDet;this.elements[5]=(a00*(a22*a33-a23*a32)-a02*(a20*a33-a23*a30)+a03*(a20*a32-a22*a30))*invDet;this.elements[6]=(-a00*(a12*a33-a13*a32)+a02*(a10*a33-a13*a30)-a03*(a10*a32-a12*a30))*invDet;this.elements[7]=(a00*(a12*a23-a13*a22)-a02*(a10*a23-a13*a20)+a03*(a10*a22-a12*a20))*invDet;this.elements[8]=(a10*(a21*a33-a23*a31)-a11*(a20*a33-a23*a30)+a13*(a20*a31-a21*a30))*invDet;this.elements[9]=(-a00*(a21*a33-a23*a31)+a01*(a20*a33-a23*a30)-a03*(a20*a31-a21*a30))*invDet;this.elements[10]=(a00*(a11*a33-a13*a31)-a01*(a10*a33-a13*a30)+a03*(a10*a31-a11*a30))*invDet;this.elements[11]=(-a00*(a11*a23-a13*a21)+a01*(a10*a23-a13*a20)-a03*(a10*a21-a11*a20))*invDet;this.elements[12]=(-a10*(a21*a32-a22*a31)+a11*(a20*a32-a22*a30)-a12*(a20*a31-a21*a30))*invDet;this.elements[13]=(a00*(a21*a32-a22*a31)-a01*(a20*a32-a22*a30)+a02*(a20*a31-a21*a30))*invDet;this.elements[14]=(-a00*(a11*a32-a12*a31)+a01*(a10*a32-a12*a30)-a02*(a10*a31-a11*a30))*invDet;this.elements[15]=(a00*(a11*a22-a12*a21)-a01*(a10*a22-a12*a20)+a02*(a10*a21-a11*a20))*invDet;return this}
transpose(){const e=this.elements;const a01=e[1],a02=e[2],a03=e[3];const a12=e[6],a13=e[7];const a23=e[11];e[1]=e[4];e[4]=a01;e[2]=e[8];e[8]=a02;e[3]=e[12];e[12]=a03;e[6]=e[9];e[9]=a12;e[7]=e[13];e[13]=a13;e[11]=e[14];e[14]=a23;return this}
lookAt(eye,target,up){const z=Vector3.subtract(eye,target).normalize();const x=Vector3.cross(up,z).normalize();const y=Vector3.cross(z,x).normalize();const e=this.elements;e[0]=x.x;e[1]=y.x;e[2]=z.x;e[3]=0;e[4]=x.y;e[5]=y.y;e[6]=z.y;e[7]=0;e[8]=x.z;e[9]=y.z;e[10]=z.z;e[11]=0;e[12]=-Vector3.dot(x,eye);e[13]=-Vector3.dot(y,eye);e[14]=-Vector3.dot(z,eye);e[15]=1;return this}
