orthographic(left,right,bottom,top,near,far){const w=right-left,h=top-bottom,d=far-near;const e=this.elements;e[0]=2/w;e[1]=0;e[2]=0;e[3]=0;e[4]=0;e[5]=2/h;e[6]=0;e[7]=0;e[8]=0;e[9]=0;e[10]=-2/d;e[11]=0;e[12]=-(right+left)/w;e[13]=-(top+bottom)/h;e[14]=-(far+near)/d;e[15]=1;return this}
compose(position,quaternion,scale){const qx=quaternion.x,qy=quaternion.y,qz=quaternion.z,qw=quaternion.w;const x2=qx*2,y2=qy*2,z2=qz*2;const xx=qx*x2,xy=qx*y2,xz=qx*z2;const yy=qy*y2,yz=qy*z2,zz=qz*z2;const wx=qw*x2,wy=qw*y2,wz=qw*z2;const sx=scale.x,sy=scale.y,sz=scale.z;const e=this.elements;e[0]=(1-(yy+zz))*sx;e[1]=(xy+wz)*sx;e[2]=(xz-wy)*sx;e[3]=0;e[4]=(xy-wz)*sy;e[5]=(1-(xx+zz))*sy;e[6]=(yz+wx)*sy;e[7]=0;e[8]=(xz+wy)*sz;e[9]=(yz-wx)*sz;e[10]=(1-(xx+yy))*sz;e[11]=0;e[12]=position.x;e[13]=position.y;e[14]=position.z;e[15]=1;return this}
decompose(position,quaternion,scale){const e=this.elements;const sx=Math.sqrt(e[0]*e[0]+e[1]*e[1]+e[2]*e[2]);const sy=Math.sqrt(e[4]*e[4]+e[5]*e[5]+e[6]*e[6]);const sz=Math.sqrt(e[8]*e[8]+e[9]*e[9]+e[10]*e[10]);const det=this.determinant();if(det<0){position.x=-position.x;position.y=-position.y;position.z=-position.z}position.x=e[12];position.y=e[13];position.z=e[14];scale.x=sx;scale.y=sy;scale.z=sz;const invSX=1/(sx||1),invSY=1/(sy||1),invSZ=1/(sz||1);const m=this.clone();m.elements[0]*=invSX;m.elements[1]*=invSX;m.elements[2]*=invSX;m.elements[4]*=invSY;m.elements[5]*=invSY;m.elements[6]*=invSY;m.elements[8]*=invSZ;m.elements[9]*=invSZ;m.elements[10]*=invSZ;quaternion.setFromRotationMatrix(m);return this}
