transformPoint(v){const e=this.elements;const x=v.x,y=v.y,z=v.z;return new Vector3(e[0]*x+e[4]*y+e[8]*z+e[12],e[1]*x+e[5]*y+e[9]*z+e[13],e[2]*x+e[6]*y+e[10]*z+e[14])}
